#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int A[20]; // N ≤ 15
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        long long ans = 0;
        for (int l = 0; l < N; ++l) {
            for (int r = l + 1; r < N; ++r) {
                int len = r - l + 1;
                if (len % 2) continue; // need even length
                int k = len / 2;
                int sub[20];
                for (int i = 0; i < len; ++i) sub[i] = A[l + i];
                int sorted[20];
                for (int i = 0; i < len; ++i) sorted[i] = sub[i];
                qsort(sorted, len, sizeof(int), cmp_int);
                // smallest k values are sorted[0..k-1]
                int minPos = len, maxPos = -1;
                for (int i = 0; i < len; ++i) {
                    // check if sub[i] is among smallest k values
                    // because values are distinct we can linear search in sorted[0..k-1]
                    for (int j = 0; j < k; ++j) {
                        if (sub[i] == sorted[j]) {
                            if (i < minPos) minPos = i;
                            if (i > maxPos) maxPos = i;
                            break;
                        }
                    }
                }
                int span = maxPos - minPos + 1;
                if (span <= k || len - span <= k) ans++;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

