import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] A = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) A[i] = Integer.parseInt(st.nextToken());
            long ans = 0;
            for (int l = 0; l < N; l++) {
                for (int r = l + 1; r < N; r++) {
                    int len = r - l + 1;
                    if ((len & 1) == 1) continue; // odd length
                    int k = len / 2;
                    int[] sub = Arrays.copyOfRange(A, l, r + 1);
                    int[] sorted = sub.clone();
                    Arrays.sort(sorted);
                    int minPos = len, maxPos = -1;
                    for (int i = 0; i < len; i++) {
                        int val = sub[i];
                        // check if val is among the k smallest
                        int idx = Arrays.binarySearch(sorted, 0, k, val);
                        if (idx >= 0) {
                            if (i < minPos) minPos = i;
                            if (i > maxPos) maxPos = i;
                        }
                    }
                    int span = maxPos - minPos + 1;
                    if (span <= k || len - span <= k) ans++;
                }
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

