let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const A = [];
  for (let i = 0; i < N; ++i) A.push(Number(input[idx++]));
  let ans = 0;
  for (let l = 0; l < N; ++l) {
    for (let r = l + 1; r < N; ++r) {
      const len = r - l + 1;
      if (len % 2 === 1) continue;
      const k = len / 2;
      const sub = A.slice(l, r + 1);
      const sorted = [...sub].sort((a, b) => a - b);
      const smallest = new Set(sorted.slice(0, k));
      let minPos = len, maxPos = -1;
      for (let i = 0; i < len; ++i) {
        if (smallest.has(sub[i])) {
          if (i < minPos) minPos = i;
          if (i > maxPos) maxPos = i;
        }
      }
      const span = maxPos - minPos + 1;
      if (span <= k || len - span <= k) ans++;
    }
  }
  outputs.push(String(ans));
}
